UPDATE unidad
SET marca = #{marca}, modelo = #{modelo}, anio = #{anio}, idTipoUnidad = #{idTipoUnidad}, numIdenInter = #{numIdenInter}
WHERE idUnidad = #{idUnidad}
AND estatus = 'ACTIVA'

UPDATE unidad
SET estatus = 'BAJA', motivoBaja = #{motivo}
WHERE idUnidad = #{idUnidad}
AND estatus = 'ACTIVA'

UPDATE unidad
SET idConductor = #{idConductor}
WHERE idUnidad = #{idUnidad}
AND estatus = 'ACTIVA'

UPDATE unidad
SET idConductor = NULL
WHERE idUnidad = #{idUnidad}
